package com.museumheist.game.entity;
public class Disruptor { private final float x,y,radius; private float remainingSeconds; public Disruptor(float x,float y,float radius,float seconds){this.x=x;this.y=y;this.radius=radius;remainingSeconds=seconds;} public boolean update(float dt){remainingSeconds=Math.max(0,remainingSeconds-dt);return remainingSeconds>0;} public boolean contains(float px,float py){return Math.hypot(px-x,py-y)<=radius;} public float getX(){return x;} public float getY(){return y;} public float getRadius(){return radius;} public float getRemainingSeconds(){return remainingSeconds;} }
